from channel1_calculators import _filter_by_time, _get_event_time
from datetime import datetime
from typing import Dict, Optional, List
import math

def calc_interval_stats(data: Dict, apply_time_dt: datetime, window_days: int = 90,
                        time_field: str = 'event_time', method: str = 'mean',
                        cond: Optional[str] = None) -> float:
    """计算窗口内连续事件时间间隔的统计指标

    DSL: interval_stats(source, window, time_field, method, cond?)

    Args:
        data: 订单数据字典
        apply_time_dt: 申请时间基准点
        window_days: 回溯窗口天数
        time_field: 事件时间字段名
        method: 统计方法
        cond: 过滤条件

    Returns:
        间隔统计值，事件不足2个时返回0.0
    """
    items = _filter_by_time(data, 'source_placeholder', apply_time_dt, window_days)
    if not isinstance(items, list) or len(items) < 2:
        return 0.0

    timestamps = sorted([_get_event_time(item, time_field) for item in items if _get_event_time(item, time_field)])
    if len(timestamps) < 2:
        return 0.0

    gaps = [(timestamps[i] - timestamps[i-1]).total_seconds() / 86400.0 for i in range(1, len(timestamps))]

    if method == 'mean':
        return round(sum(gaps) / len(gaps), 2)
    elif method == 'std':
        mean_val = sum(gaps) / len(gaps)
        variance = sum((x - mean_val) ** 2 for x in gaps) / len(gaps)
        return round(math.sqrt(variance), 2)
    elif method == 'median':
        sorted_gaps = sorted(gaps)
        mid = len(sorted_gaps) // 2
        return round((sorted_gaps[mid] + sorted_gaps[~mid]) / 2.0, 2)
    elif method == 'cv':
        mean_val = sum(gaps) / len(gaps)
        if mean_val == 0:
            return 0.0
        variance = sum((x - mean_val) ** 2 for x in gaps) / len(gaps)
        return round(math.sqrt(variance) / mean_val, 4)
    elif method == 'min_gap':
        return round(min(gaps), 2)
    elif method == 'max_gap':
        return round(max(gaps), 2)
    return 0.0

from channel1_calculators import _filter_by_time
from typing import Dict, Optional
import math

def calc_value_stats(data: Dict, apply_time_dt: datetime, window_days: int = 90,
                     value_field: str = 'amount', method: str = 'mean',
                     cond: Optional[str] = None, min_count: int = 1) -> float:
    """对窗口内数值字段进行基础聚合统计

    DSL: value_stats(source, window, value_field, method, cond?, min_count)

    Args:
        data: 订单数据字典
        apply_time_dt: 申请时间基准点
        window_days: 回溯窗口天数
        value_field: 目标数值字段名
        method: 统计方法
        cond: 过滤条件
        min_count: 最小有效样本数

    Returns:
        统计结果浮点数，样本不足时返回0.0
    """
    items = _filter_by_time(data, 'source_placeholder', apply_time_dt, window_days)
    if not isinstance(items, list):
        return 0.0

    values = []
    for item in items:
        val = item.get(value_field)
        if val is not None:
            try:
                values.append(float(val))
            except (ValueError, TypeError):
                continue

    if len(values) < min_count:
        return 0.0

    if method == 'sum':
        return round(sum(values), 2)
    elif method == 'mean':
        return round(sum(values) / len(values), 2)
    elif method == 'max':
        return round(max(values), 2)
    elif method == 'min':
        return round(min(values), 2)
    elif method == 'std':
        mean_val = sum(values) / len(values)
        variance = sum((x - mean_val) ** 2 for x in values) / len(values)
        return round(math.sqrt(variance), 2)
    return 0.0

def calc_interval_stat(data: Dict, apply_time_dt: datetime, window_days: int = 30,
                         source: str = 'fdc_pinjaman', time_field: str = 'event_time',
                         stat_method: str = 'mean') -> float:
    """计算事件序列相邻时间间隔的统计量（防穿越设计）

    DSL: interval_stat(source, time_field, window, stat_method)

    Args:
        data: 订单数据
        apply_time_dt: 申请时间
        window_days: 回溯窗口天数
        source: 数据源标识
        time_field: 时间字段名
        stat_method: 统计方法 (min, mean, std, median)

    Returns:
        间隔统计值（天）
    """
    import statistics
    from channel1_calculators import _filter_by_time, _get_event_time

    items = _filter_by_time(data, source, apply_time_dt, window_days)
    if not isinstance(items, list):
        return 0.0

    timestamps = []
    for item in items:
        t = _get_event_time(item, time_field)
        if t <= apply_time_dt:
            timestamps.append(t)

    if len(timestamps) < 2:
        return 0.0  # 不足两次事件无法计算间隔

    timestamps.sort()
    diffs = [(timestamps[i+1] - timestamps[i]).total_seconds() / 86400.0 for i in range(len(timestamps)-1)]

    if stat_method == 'min':
        return float(min(diffs))
    elif stat_method == 'mean':
        return float(statistics.mean(diffs))
    elif stat_method == 'std':
        return float(statistics.stdev(diffs)) if len(diffs) > 1 else 0.0
    elif stat_method == 'median':
        return float(statistics.median(diffs))
    else:
        return float(statistics.mean(diffs))
